import{_ as t,o as e,c as a,ae as r}from"./chunks/framework.BzQXgbNp.js";const n="/assets/dash-2.4mhzNEdv.png",_=JSON.parse('{"title":"🔍 網頁端商店導航與瀏覽","description":"","frontmatter":{},"headers":[],"relativePath":"Web-Shop-Navigation.md","filePath":"Web-Shop-Navigation.md"}'),s={name:"Web-Shop-Navigation.md"};function i(l,o,d,c,g,p){return e(),a("div",null,[...o[0]||(o[0]=[r('<h1 id="🔍-網頁端商店導航與瀏覽" tabindex="-1">🔍 網頁端商店導航與瀏覽 <a class="header-anchor" href="#🔍-網頁端商店導航與瀏覽" aria-label="Permalink to &quot;🔍 網頁端商店導航與瀏覽&quot;">​</a></h1><p>玩家可以使用網頁版「商店瀏覽器」，快速尋找並導航至全服的所有玩家擺攤。</p><p><img src="'+n+'" alt="網頁商店瀏覽器"></p><hr><h2 id="🛍️-1-商店列表與搜尋" tabindex="-1">🛍️ 1. 商店列表與搜尋 <a class="header-anchor" href="#🛍️-1-商店列表與搜尋" aria-label="Permalink to &quot;🛍️ 1. 商店列表與搜尋&quot;">​</a></h2><p>在網頁端 <strong>「商店瀏覽器」</strong> 頁面中：</p><ul><li><strong>即時列表</strong>：系統會羅列出目前所有營業中的玩家箱子商店。</li><li><strong>商品搜尋</strong>：在搜尋欄中輸入關鍵字，即可快速篩選指定商品（如 <code>DIAMOND</code>、<code>GLASS</code> 等）。</li><li><strong>排序功能</strong>：支援依照價格（從低到高/從高到低）或庫存剩餘量進行排序，方便貨比三家。</li></ul><hr><h2 id="🧭-2-遊戲內快速傳送導航" tabindex="-1">🧭 2. 遊戲內快速傳送導航 <a class="header-anchor" href="#🧭-2-遊戲內快速傳送導航" aria-label="Permalink to &quot;🧭 2. 遊戲內快速傳送導航&quot;">​</a></h2><p>當您在網頁上找到心儀的商店後：</p><ol><li>點擊商店卡片上的 <strong>「座標標籤」</strong>（例如 <code>100, 64, -200</code>）。</li><li>系統會自動複製遊戲內的傳送指令 <strong><code>/tp &lt;X&gt; &lt;Y&gt; &lt;Z&gt;</code></strong> 至您的剪貼簿。</li><li><strong>⚠️ 傳送權限限制說明</strong>： <ul><li><strong>OP 管理員</strong>：進入遊戲直接在聊天欄貼上並送出 <code>/tp</code> 指令，即可瞬間傳送至該商店前進行交易。</li><li><strong>普通玩家</strong>：普通玩家在伺服器中<strong>無 <code>/tp</code> 權限</strong>，若貼上會顯示權限不足。普通玩家請在遊戲內輸入 <strong><code>/shop</code></strong> 指令開啟選單，找到該商店並點選 <strong><code>[傳送到商店]</code></strong> 進行安全傳送。</li></ul></li></ol>',11)])])}const m=t(s,[["render",i]]);export{_ as __pageData,m as default};
